    Example:
    histogram('a b c') == {'a': 1, 'b': 1, 'c': 1}
    histogram('a b b a') == {'a': 2, 'b': 2}
    histogram('a b c a b') == {'a': 2, 'b': 2}
    histogram('b b b b a') == {'b': 4}
    histogram('') == {}

    """
    if not test:
        return {}

    dict1 = {}
    list1 = test.split(" ")
    max_count = 0

    for i in set(list1):
        count = list1.count(i)
        if count > max_count:
            max_count = count
